"""Provider-neutral launch preflight validation and audit-event builders."""

from __future__ import annotations

from dataclasses import dataclass

from scc_cli.application.start_session import StartSessionPlan
from scc_cli.core.contracts import AgentLaunchSpec, AuditEvent
from scc_cli.core.enums import NetworkPolicy, SeverityLevel
from scc_cli.core.errors import (
    InvalidLaunchPlanError,
    LaunchPolicyBlockedError,
    LaunchPreflightError,
)
from scc_cli.ports.models import SandboxHandle


@dataclass(frozen=True)
class LaunchPreflightDecision:
    """Validated launch metadata used by the launch boundary."""

    provider_id: str
    network_policy: str
    required_destination_sets: tuple[str, ...]
    audit_event: AuditEvent


def evaluate_launch_preflight(plan: StartSessionPlan) -> LaunchPreflightDecision:
    """Validate that the prepared launch plan can start under the current policy."""
    spec = _validated_launch_spec(plan)
    provider_id = _validated_provider_id(spec.provider_id)
    required_destination_sets = _validated_required_destination_sets(spec.required_destination_sets)
    network_policy = _effective_network_policy(plan)

    if (
        network_policy == NetworkPolicy.LOCKED_DOWN_WEB.value
        and len(required_destination_sets) > 0
    ):
        raise LaunchPolicyBlockedError(
            provider_id=provider_id,
            network_policy=network_policy,
            required_destination_sets=required_destination_sets,
        )

    return LaunchPreflightDecision(
        provider_id=provider_id,
        network_policy=network_policy,
        required_destination_sets=required_destination_sets,
        audit_event=AuditEvent(
            event_type="launch.preflight.passed",
            message=f"Launch preflight passed for provider '{provider_id}'.",
            severity=SeverityLevel.INFO,
            subject=provider_id,
            metadata=_event_metadata(
                plan,
                provider_id=provider_id,
                network_policy=network_policy,
                required_destination_sets=required_destination_sets,
            ),
        ),
    )


def build_preflight_failure_event(
    plan: StartSessionPlan,
    error: LaunchPreflightError,
) -> AuditEvent:
    """Build the canonical audit event for a failed launch preflight."""
    provider_id = _safe_provider_id(plan)
    required_destination_sets = _safe_required_destination_sets(plan)
    network_policy = _effective_network_policy(plan)
    metadata = _event_metadata(
        plan,
        provider_id=provider_id,
        network_policy=network_policy,
        required_destination_sets=required_destination_sets,
    )
    metadata["failure_reason"] = error.user_message
    return AuditEvent(
        event_type="launch.preflight.failed",
        message=(
            f"Launch preflight failed for provider '{provider_id or 'unknown'}'."
        ),
        severity=SeverityLevel.ERROR,
        subject=provider_id or None,
        metadata=metadata,
    )


def build_launch_started_event(
    plan: StartSessionPlan,
    decision: LaunchPreflightDecision,
    handle: SandboxHandle,
) -> AuditEvent:
    """Build the canonical audit event for a successful runtime handoff."""
    metadata = _event_metadata(
        plan,
        provider_id=decision.provider_id,
        network_policy=decision.network_policy,
        required_destination_sets=decision.required_destination_sets,
    )
    metadata["sandbox_id"] = handle.sandbox_id
    if handle.name:
        metadata["sandbox_name"] = handle.name
    return AuditEvent(
        event_type="launch.started",
        message=f"Launch started for provider '{decision.provider_id}'.",
        severity=SeverityLevel.INFO,
        subject=decision.provider_id,
        metadata=metadata,
    )


def _validated_launch_spec(plan: StartSessionPlan) -> AgentLaunchSpec:
    spec = plan.agent_launch_spec
    if spec is None:
        raise InvalidLaunchPlanError(
            reason="Launch plan is missing provider launch metadata.",
        )
    return spec


def _validated_provider_id(provider_id: str) -> str:
    normalized = provider_id.strip()
    if normalized == "":
        raise InvalidLaunchPlanError(
            reason="Launch plan is missing provider identity.",
        )
    return normalized


def _validated_required_destination_sets(required_destination_sets: tuple[str, ...]) -> tuple[str, ...]:
    normalized: list[str] = []
    for destination_set in required_destination_sets:
        cleaned = destination_set.strip()
        if cleaned == "":
            raise InvalidLaunchPlanError(
                reason="Launch plan contains a blank required destination set name.",
            )
        normalized.append(cleaned)
    return tuple(normalized)


def _effective_network_policy(plan: StartSessionPlan) -> str:
    sandbox_spec = plan.sandbox_spec
    if sandbox_spec is None or sandbox_spec.network_policy is None:
        return NetworkPolicy.OPEN.value
    return sandbox_spec.network_policy


def _safe_provider_id(plan: StartSessionPlan) -> str:
    spec = plan.agent_launch_spec
    if spec is None:
        return ""
    return spec.provider_id.strip()


def _safe_required_destination_sets(plan: StartSessionPlan) -> tuple[str, ...]:
    spec = plan.agent_launch_spec
    if spec is None:
        return ()
    return tuple(destination_set.strip() for destination_set in spec.required_destination_sets)


def _event_metadata(
    plan: StartSessionPlan,
    *,
    provider_id: str,
    network_policy: str,
    required_destination_sets: tuple[str, ...],
) -> dict[str, str]:
    return {
        "provider_id": provider_id,
        "network_policy": network_policy,
        "required_destination_sets": ",".join(required_destination_sets),
        "workspace_path": str(plan.workspace_path),
        "session_name": plan.session_name or "",
        "team": plan.team or "",
    }

"""Finalize launch use case for start flows."""

from __future__ import annotations

from scc_cli.application.launch.preflight import (
    build_launch_started_event,
    build_preflight_failure_event,
    evaluate_launch_preflight,
)
from scc_cli.application.start_session import (
    StartSessionDependencies,
    StartSessionPlan,
    start_session,
)
from scc_cli.core.contracts import AuditEvent
from scc_cli.core.errors import (
    LaunchAuditUnavailableError,
    LaunchAuditWriteError,
    LaunchPreflightError,
)
from scc_cli.ports.audit_event_sink import AuditEventSink
from scc_cli.ports.models import SandboxHandle

FinalizeLaunchDependencies = StartSessionDependencies
FinalizeLaunchPlan = StartSessionPlan
FinalizeLaunchResult = SandboxHandle


def finalize_launch(
    plan: FinalizeLaunchPlan,
    *,
    dependencies: FinalizeLaunchDependencies,
) -> FinalizeLaunchResult:
    """Finalize a prepared launch plan by validating then starting the sandbox."""
    if _uses_preflight_seam(plan, dependencies):
        sink = dependencies.audit_event_sink
        if sink is None:
            raise LaunchAuditUnavailableError()
        try:
            decision = evaluate_launch_preflight(plan)
        except LaunchPreflightError as error:
            _append_audit_event(sink, build_preflight_failure_event(plan, error))
            raise
        _append_audit_event(sink, decision.audit_event)
        handle = start_session(plan, dependencies=dependencies)
        _append_audit_event(sink, build_launch_started_event(plan, decision, handle))
        return handle
    return start_session(plan, dependencies=dependencies)


def _uses_preflight_seam(
    plan: FinalizeLaunchPlan,
    dependencies: FinalizeLaunchDependencies,
) -> bool:
    return plan.agent_launch_spec is not None or dependencies.audit_event_sink is not None


def _append_audit_event(sink: AuditEventSink, event: AuditEvent) -> None:
    try:
        sink.append(event)
    except Exception as exc:  # pragma: no cover - defensive wrapper over sink adapters
        raise LaunchAuditWriteError(
            audit_destination=sink.describe_destination(),
            event_type=event.event_type,
            reason=str(exc),
        ) from exc

"""Port for durable audit-event persistence."""

from __future__ import annotations

from typing import Protocol

from scc_cli.core.contracts import AuditEvent


class AuditEventSink(Protocol):
    """Persist canonical audit events to a durable sink."""

    def append(self, event: AuditEvent) -> None:
        """Append one audit event to the sink."""

    def describe_destination(self) -> str:
        """Return a human-readable destination description for error messages."""

"""
Typed exceptions for SCC - Sandboxed Claude CLI.

Error handling philosophy: "One message, one action"
- Each error has a clear user_message (what went wrong)
- Each error has a suggested_action (what to do next)
- Debug context is available with --debug flag

Exit codes:
- 0: Success
- 2: Invalid usage / bad input
- 3: Missing prerequisites (Docker, Git)
- 4: External tool failure (docker/git command failed)
- 5: Internal error (bug)
"""

import shlex
from dataclasses import dataclass, field


@dataclass
class SCCError(Exception):
    """Base error with user-friendly messaging."""

    user_message: str
    suggested_action: str = ""
    debug_context: str | None = None
    exit_code: int = 1

    def __str__(self) -> str:
        return self.user_message


@dataclass
class UsageError(SCCError):
    """Invalid usage or bad input."""

    exit_code: int = field(default=2, init=False)


@dataclass
class PrerequisiteError(SCCError):
    """Docker/Git missing or wrong version."""

    exit_code: int = field(default=3, init=False)


@dataclass
class DockerNotFoundError(PrerequisiteError):
    """Docker is not installed or not in PATH."""

    user_message: str = field(default="Docker is not installed or not in PATH")
    suggested_action: str = field(
        default="Install Docker Desktop from https://docker.com/products/docker-desktop"
    )


@dataclass
class DockerDaemonNotRunningError(PrerequisiteError):
    """Docker Desktop is installed but not running."""

    user_message: str = field(default="Docker Desktop is not running")
    suggested_action: str = field(default="Start Docker Desktop and try again")


@dataclass
class DockerVersionError(PrerequisiteError):
    """Docker version is too old for sandbox feature."""

    current_version: str = ""
    required_version: str = "4.50.0"
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Update Docker Desktop from https://docker.com/products/docker-desktop"
    )

    def __post_init__(self) -> None:
        if not self.user_message:
            self.user_message = (
                f"Docker Desktop {self.required_version}+ required for sandbox support\n"
                f"Current: {self.current_version or 'unknown'} | Required: {self.required_version}+"
            )


@dataclass
class SandboxNotAvailableError(PrerequisiteError):
    """Docker sandbox feature is not available."""

    user_message: str = field(default="Docker sandbox feature is not available")
    suggested_action: str = field(
        default=(
            "Ensure Docker Desktop 4.50+ is installed and the sandbox CLI is available. "
            "Run 'docker sandbox --help' to verify and check your PATH for Docker Desktop."
        )
    )


@dataclass
class GitNotFoundError(PrerequisiteError):
    """Git is not installed or not in PATH."""

    user_message: str = field(default="Git is not installed or not in PATH")
    suggested_action: str = field(default="Install Git from https://git-scm.com/downloads")


@dataclass
class ToolError(SCCError):
    """External tool (Docker/Git) command failed."""

    exit_code: int = field(default=4, init=False)
    command: str | None = None
    stderr: str | None = None

    def __post_init__(self) -> None:
        if self.command or self.stderr:
            parts = []
            if self.command:
                parts.append(f"Command: {self.command}")
            if self.stderr:
                parts.append(f"Error: {self.stderr}")
            self.debug_context = "\n".join(parts)


@dataclass
class WorkspaceError(ToolError):
    """Invalid workspace path or clone failed."""

    user_message: str = field(default="Workspace error")


@dataclass
class WorkspaceNotFoundError(WorkspaceError):
    """Workspace path does not exist."""

    path: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Check the path exists or create the directory")

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.path:
            self.user_message = f"Workspace not found: {self.path}"


@dataclass
class NotAGitRepoError(WorkspaceError):
    """Path is not a git repository."""

    path: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Initialize git with 'git init' or clone a repository")

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.path:
            self.user_message = f"Not a git repository: {self.path}"


@dataclass
class CloneError(WorkspaceError):
    """Git clone failed."""

    url: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(default="Check the repository URL and your network connection")

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.url:
            self.user_message = f"Failed to clone repository: {self.url}"


@dataclass
class GitWorktreeError(ToolError):
    """Worktree creation/cleanup failed."""

    user_message: str = field(default="Git worktree operation failed")


@dataclass
class WorktreeExistsError(GitWorktreeError):
    """Worktree already exists."""

    path: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Use existing worktree, remove it first, or choose a different name"
    )

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.path:
            self.user_message = f"Worktree already exists: {self.path}"


@dataclass
class WorktreeCreationError(GitWorktreeError):
    """Failed to create worktree."""

    name: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Check if the branch already exists or if there are uncommitted changes"
    )

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.name:
            self.user_message = f"Failed to create worktree: {self.name}"


@dataclass
class SandboxLaunchError(ToolError):
    """Docker sandbox failed to start."""

    exit_code: int = field(default=5, init=False)
    user_message: str = field(default="Failed to start Docker sandbox")
    suggested_action: str = field(
        default="Check Docker Desktop is running and has available resources"
    )

    def __post_init__(self) -> None:
        # Call parent to set debug_context from command/stderr
        super().__post_init__()
        # Always show stderr in suggested_action (don't hide behind debug flag)
        if self.stderr and self.stderr.strip():
            self.suggested_action = (
                f"{self.suggested_action}\n\nDocker error: {self.stderr.strip()}"
            )


@dataclass
class ContainerNotFoundError(ToolError):
    """Container does not exist (for resume operations)."""

    container_name: str = ""
    user_message: str = field(default="")
    suggested_action: str = field(
        default="Start a new session or check 'scc list' for available containers"
    )

    def __post_init__(self) -> None:
        super().__post_init__()
        if not self.user_message and self.container_name:
            self.user_message = f"Container not found: {self.container_name}"


@dataclass
class InternalError(SCCError):
    """Internal error (bug in the CLI)."""

    exit_code: int = field(default=5, init=False)
    suggested_action: str = field(
        default="Please report this issue at https://github.com/CCimen/scc/issues"
    )


@dataclass
class ConfigError(SCCError):
    """Configuration error."""

